const LOGO_MAP = { warriors: warriorsLogo, gladiators: gladiatorsLogo, titans: titansLogo };

function computeRating(ratingsMap) {
  const entries = Object.values(ratingsMap || {});
  if (!entries.length) return 0;
  const total = entries.reduce((sum, r) => sum + r.stars, 0);
  return Math.min(5, Math.max(0, total / entries.length));
}

function StarRating({ value, onChange, size = 20 }) {
  const [hovered, setHovered] = useState(0);
  return (
    <div style={{ display: "flex", gap: 2 }}>
      {[1, 2, 3, 4, 5].map((s) => (
        <span key={s}
          onClick={() => onChange && onChange(s)}
          onMouseEnter={() => onChange && setHovered(s)}
          onMouseLeave={() => onChange && setHovered(0)}
          style={{ fontSize: size, cursor: onChange ? "pointer" : "default", color: s <= (hovered || Math.round(value)) ? "#e8a020" : "#333", transition: "color 0.12s", userSelect: "none" }}
        >★</span>
      ))}
    </div>
  );
}

function Avatar({ name, img, size = 56, color = "#1d2d5a", accent = "#4dc8c8" }) {
  const initials = name.split(" ").map((w) => w[0]).join("").slice(0, 2).toUpperCase();
  if (img) return <img src={img} alt={name} style={{ width: size, height: size, borderRadius: "50%", objectFit: "cover", border: `2px solid ${accent}` }} />;
  return (
    <div style={{ width: size, height: size, borderRadius: "50%", background: color, color: accent, display: "flex", alignItems: "center", justifyContent: "center", fontSize: size * 0.33, fontWeight: 800, flexShrink: 0, border: `2px solid ${accent}`, fontFamily: "Georgia, serif" }}>
      {initials}
    </div>
  );
}

function ClubLogo({ clubId, size = 48 }) {
  const src = LOGO_MAP[clubId];
  if (!src) return null;
  return <img src={src} alt={clubId} style={{ width: size, height: size, objectFit: "contain", borderRadius: 8 }} />;
}

export default function App() {
  const [clubData, setClubData] = useState(() => {
    try { const s = localStorage.getItem("uc_data_v2"); return s ? JSON.parse(s) : SEED_DATA; } catch { return SEED_DATA; }
  });
  const [ratings, setRatings] = useState(() => {
    try { return JSON.parse(localStorage.getItem("uc_ratings_v2") || "{}"); } catch { return {}; }
  });
  const [comments, setComments] = useState(() => {
    try { return JSON.parse(localStorage.getItem("uc_comments_v2") || "{}"); } catch { return {}; }
  });
  const [view, setView] = useState("home");
  const [activeClub, setActiveClub] = useState(null);
  const [activeMatchday, setActiveMatchday] = useState(null);
  const [isAdmin, setIsAdmin] = useState(false);
  const [adminModal, setAdminModal] = useState(false);
  const [adminPass, setAdminPass] = useState("");
  const [adminErr, setAdminErr] = useState("");
  const [fanId] = useState(() => {
    let id = localStorage.getItem("uc_fan_id");
    if (!id) { id = "fan_" + Math.random().toString(36).slice(2, 10); localStorage.setItem("uc_fan_id", id); }
    return id;
  });

  useEffect(() => { localStorage.setItem("uc_data_v2", JSON.stringify(clubData)); }, [clubData]);
  useEffect(() => { localStorage.setItem("uc_ratings_v2", JSON.stringify(ratings)); }, [ratings]);
  useEffect(() => { localStorage.setItem("uc_comments_v2", JSON.stringify(comments)); }, [comments]);

  const getPlayerRating = useCallback((clubId, playerId) => computeRating(ratings[`${clubId}_${playerId}`] || {}), [ratings]);
  const getMatchdayRating = useCallback((clubId, matchdayId, playerId) => computeRating(ratings[`${clubId}_${matchdayId}_${playerId}`] || {}), [ratings]);

  const ratePlayer = (clubId, matchdayId, playerId, stars) => {
    const mdKey = `${clubId}_${matchdayId}_${playerId}`;
    const overallKey = `${clubId}_${playerId}`;
    setRatings((prev) => ({
      ...prev,
      [mdKey]: { ...(prev[mdKey] || {}), [fanId]: { stars, ts: Date.now() } },
      [overallKey]: { ...(prev[overallKey] || {}), [`${fanId}_${matchdayId}`]: { stars, ts: Date.now() } },
    }));
  };

  const addComment = (clubId, matchdayId, playerId, text) => {
    const key = `${clubId}_${matchdayId}_${playerId}`;
    setComments((prev) => ({ ...prev, [key]: [...(prev[key] || []), { id: Date.now(), fanId, text, ts: new Date().toLocaleString() }] }));
  };

  const updateClub = (clubId, updater) => setClubData((prev) => ({ ...prev, [clubId]: updater(prev[clubId]) }));

  const club = activeClub ? CLUBS.find((c) => c.id === activeClub) : null;
  const data = activeClub ? clubData[activeClub] : null;

  // App-wide theme uses Warriors FC colors as base
  const appStyle = { minHeight: "100vh", fontFamily: "'Segoe UI', system-ui, sans-serif", background: "#060810", color: "#f0f0f0" };

  return (
    <div style={appStyle}>
      <Header view={view} setView={setView} activeClub={club} setActiveClub={setActiveClub}
        setActiveMatchday={setActiveMatchday} isAdmin={isAdmin}
        onAdminClick={() => isAdmin ? setIsAdmin(false) : setAdminModal(true)} />
      {adminModal && (
        <AdminLoginModal pass={adminPass} setPass={setAdminPass} err={adminErr}
          onLogin={() => { if (adminPass === ADMIN_PASSWORD) { setIsAdmin(true); setAdminModal(false); setAdminErr(""); setAdminPass(""); } else setAdminErr("Incorrect password."); }}
          onClose={() => { setAdminModal(false); setAdminErr(""); setAdminPass(""); }} />
      )}
      {view === "home" && <HomePage clubs={CLUBS} clubData={clubData} getPlayerRating={getPlayerRating} onEnterClub={(id) => { setActiveClub(id); setView("club"); }} />}
      {view === "club" && club && data && (
        <ClubPage club={club} data={data} isAdmin={isAdmin} getPlayerRating={getPlayerRating}
          onMatchday={(md) => { setActiveMatchday(md); setView("matchday"); }}
          updateClub={(fn) => updateClub(club.id, fn)} />
      )}
      {view === "matchday" && club && data && activeMatchday && (
        <MatchdayPage club={club} data={data} matchday={data.matchdays.find((m) => m.id === activeMatchday)}
          isAdmin={isAdmin} fanId={fanId}
          getMatchdayRating={(pid) => getMatchdayRating(club.id, activeMatchday, pid)}
          ratePlayer={(pid, stars) => ratePlayer(club.id, activeMatchday, pid, stars)}
          getComments={(pid) => (comments[`${club.id}_${activeMatchday}_${pid}`] || [])}
          addComment={(pid, text) => addComment(club.id, activeMatchday, pid, text)}
          updateClub={(fn) => updateClub(club.id, fn)} />
      )}
    </div>
  );
}

// ─── HEADER ───────────────────────────────────────────────────────────────────
function Header({ view, setView, activeClub, setActiveClub, setActiveMatchday, isAdmin, onAdminClick }) {
  return (
    <header style={{ background: "#0a0d1a", borderBottom: "1px solid #1d2d5a", padding: "0 20px", display: "flex", alignItems: "center", justifyContent: "space-between", height: 58, position: "sticky", top: 0, zIndex: 100 }}>
      <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
        {view !== "home" && (
          <button onClick={() => { if (view === "matchday") { setView("club"); setActiveMatchday(null); } else { setView("home"); setActiveClub(null); } }}
            style={{ background: "none", border: "none", color: "#4dc8c8", cursor: "pointer", fontSize: 22, padding: "4px 8px", lineHeight: 1 }}>←</button>
        )}
        <div onClick={() => { setView("home"); setActiveClub(null); setActiveMatchday(null); }} style={{ cursor: "pointer", display: "flex", alignItems: "center", gap: 10 }}>
          <ClubLogo clubId="warriors" size={36} />
          <div>
            <div style={{ fontWeight: 800, fontSize: 13, color: "#4dc8c8", letterSpacing: 1, lineHeight: 1 }}>URBAN CIRCLE</div>
            <div style={{ fontWeight: 600, fontSize: 10, color: "#e8457a", letterSpacing: 2 }}>SPORTS PLATFORM</div>
          </div>
        </div>
        {activeClub && <><span style={{ color: "#1d2d5a", fontSize: 20 }}>›</span><span style={{ color: "#4dc8c8", fontSize: 13, fontWeight: 700 }}>{activeClub.short}</span></>}
      </div>
      <button onClick={onAdminClick} style={{ background: isAdmin ? "#e8457a" : "transparent", border: `1px solid ${isAdmin ? "#e8457a" : "#1d2d5a"}`, color: isAdmin ? "#fff" : "#4dc8c8", borderRadius: 6, padding: "5px 14px", fontSize: 12, cursor: "pointer", fontWeight: 700 }}>
        {isAdmin ? "🔓 Admin Mode" : "Admin Login"}
      </button>
    </header>
  );
}

// ─── ADMIN LOGIN ──────────────────────────────────────────────────────────────
function AdminLoginModal({ pass, setPass, err, onLogin, onClose }) {
  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.9)", zIndex: 999, display: "flex", alignItems: "center", justifyContent: "center" }}>
      <div style={{ background: "#0a0d1a", border: "1px solid #1d2d5a", borderRadius: 14, padding: 32, width: 320 }}>
        <div style={{ display: "flex", justifyContent: "center", marginBottom: 16 }}><ClubLogo clubId="warriors" size={56} /></div>
        <h3 style={{ margin: "0 0 16px", color: "#4dc8c8", textAlign: "center" }}>Admin Access</h3>
        <input type="password" placeholder="Enter admin password" value={pass} onChange={(e) => setPass(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && onLogin()}
          style={{ width: "100%", padding: "10px 12px", borderRadius: 8, border: "1px solid #1d2d5a", background: "#060810", color: "#f0f0f0", fontSize: 14, boxSizing: "border-box", marginBottom: 8 }} />
        {err && <p style={{ color: "#e8457a", fontSize: 13, margin: "0 0 8px" }}>{err}</p>}
        <div style={{ display: "flex", gap: 8, marginTop: 8 }}>
          <button onClick={onLogin} style={{ flex: 1, padding: "10px", background: "#1d2d5a", border: "1px solid #4dc8c8", borderRadius: 8, fontWeight: 700, cursor: "pointer", color: "#4dc8c8" }}>Login</button>
          <button onClick={onClose} style={{ flex: 1, padding: "10px", background: "transparent", border: "1px solid #1d2d5a", borderRadius: 8, cursor: "pointer", color: "#666" }}>Cancel</button>
        </div>
      </div>
    </div>
  );
}

// ─── HOME PAGE ────────────────────────────────────────────────────────────────
function HomePage({ clubs, clubData, getPlayerRating, onEnterClub }) {
  return (
    <main style={{ maxWidth: 1160, margin: "0 auto", padding: "32px 20px" }}>
      {/* Hero banner using Warriors colors */}
      <div style={{ background: "linear-gradient(135deg, #0a0d1a 0%, #1d2d5a 60%, #0a1530 100%)", borderRadius: 20, padding: "32px 40px", marginBottom: 40, display: "flex", alignItems: "center", gap: 32, overflow: "hidden", position: "relative", border: "1px solid #1d2d5a" }}>
        <div style={{ position: "absolute", right: -20, top: -20, width: 200, height: 200, borderRadius: "50%", background: "radial-gradient(circle, rgba(77,200,200,0.08) 0%, transparent 70%)" }} />
        <div style={{ position: "absolute", right: 80, bottom: -40, width: 160, height: 160, borderRadius: "50%", background: "radial-gradient(circle, rgba(232,69,122,0.06) 0%, transparent 70%)" }} />
        <div style={{ display: "flex", gap: 16, flexShrink: 0 }}>
          {clubs.map((c) => <ClubLogo key={c.id} clubId={c.id} size={64} />)}
        </div>
        <div>
          <h1 style={{ margin: 0, fontSize: 32, fontWeight: 900, color: "#fff", lineHeight: 1.1 }}>
            <span style={{ color: "#4dc8c8" }}>Urban Circle</span> Sports
          </h1>
          <p style={{ margin: "8px 0 0", color: "#e8457a", fontSize: 14, fontWeight: 600, letterSpacing: 1 }}>FAN ENGAGEMENT PLATFORM · RATE · COMMENT · CELEBRATE</p>
        </div>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(340px, 1fr))", gap: 24 }}>
        {clubs.map((club) => {
          const data = clubData[club.id];
          const players = data?.players || [];
          const sorted = [...players].sort((a, b) => getPlayerRating(club.id, b.id) - getPlayerRating(club.id, a.id));
          return (
            <ClubCard key={club.id} club={club} data={data} leaderboard={sorted.slice(0, 5)}
              getPlayerRating={(pid) => getPlayerRating(club.id, pid)} onEnter={() => onEnterClub(club.id)} />
          );
        })}
      </div>
    </main>
  );
}

function ClubCard({ club, data, leaderboard, getPlayerRating, onEnter }) {
  const headlines = data?.headlines || [];
  return (
    <div style={{ background: "#0a0d1a", border: `1px solid ${club.primary}`, borderRadius: 18, overflow: "hidden", display: "flex", flexDirection: "column" }}>
      {/* Club header */}
      <div style={{ background: club.primary, padding: "20px", borderBottom: `3px solid ${club.accent}`, display: "flex", alignItems: "center", gap: 14 }}>
        <ClubLogo clubId={club.id} size={60} />
        <div>
          <div style={{ fontWeight: 900, fontSize: 15, color: "#fff", lineHeight: 1.2 }}>{club.name}</div>
          <div style={{ fontSize: 11, color: club.accent, fontWeight: 700, marginTop: 3, letterSpacing: 0.5 }}>{club.sport}</div>
          <div style={{ fontSize: 11, color: club.highlight === "#ffffff" ? "rgba(255,255,255,0.5)" : club.highlight, marginTop: 2 }}>{club.tagline}</div>
        </div>
      </div>

      {/* Headlines */}
      {headlines.length > 0 && (
        <div style={{ padding: "12px 16px", borderBottom: `1px solid ${club.primary}20` }}>
          <div style={{ fontSize: 10, color: club.accent, fontWeight: 800, letterSpacing: 1.5, textTransform: "uppercase", marginBottom: 8 }}>Latest News</div>
          {headlines.slice(0, 2).map((h) => (
            <div key={h.id} style={{ fontSize: 12, color: "#bbb", lineHeight: 1.4, marginBottom: 5, paddingLeft: 10, borderLeft: `2px solid ${club.accent}` }}>
              {h.title}
            </div>
          ))}
        </div>
      )}

      {/* Leaderboard */}
      <div style={{ padding: "12px 16px", flex: 1 }}>
        <div style={{ fontSize: 10, color: club.accent, fontWeight: 800, letterSpacing: 1.5, textTransform: "uppercase", marginBottom: 10 }}>Fan Leaderboard</div>
        {leaderboard.length === 0 && <div style={{ color: "#333", fontSize: 13, fontStyle: "italic" }}>No players rated yet</div>}
        {leaderboard.map((p, i) => {
          const rating = getPlayerRating(p.id);
          const medals = ["🥇", "🥈", "🥉", "4.", "5."];
          return (
            <div key={p.id} style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 9, padding: "6px 8px", borderRadius: 8, background: i === 0 ? `${club.primary}40` : "transparent" }}>
              <span style={{ fontSize: 14, width: 20, textAlign: "center", flexShrink: 0 }}>{medals[i]}</span>
              <Avatar name={p.name} img={p.img} size={30} color={club.primary} accent={club.accent} />
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontSize: 12, fontWeight: 700, color: "#e0e0e0", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{p.name}</div>
                <div style={{ fontSize: 10, color: "#555" }}>{p.position}</div>
              </div>
              <div style={{ textAlign: "right", flexShrink: 0 }}>
                <StarRating value={rating} size={11} />
                <div style={{ fontSize: 10, color: "#666" }}>{rating.toFixed(1)}</div>
              </div>
            </div>
          );
        })}
      </div>

      <div style={{ padding: "0 16px 16px" }}>
        <button onClick={onEnter} style={{ width: "100%", padding: "11px", background: club.primary, border: `1.5px solid ${club.accent}`, borderRadius: 10, color: club.accent, fontWeight: 800, cursor: "pointer", fontSize: 13, letterSpacing: 0.5, transition: "all 0.2s" }}
          onMouseEnter={(e) => { e.currentTarget.style.background = club.accent; e.currentTarget.style.color = "#fff"; }}
          onMouseLeave={(e) => { e.currentTarget.style.background = club.primary; e.currentTarget.style.color = club.accent; }}>
          Enter {club.short} →
        </button>
      </div>
    </div>
  );
}

// ─── CLUB PAGE ────────────────────────────────────────────────────────────────
function ClubPage({ club, data, isAdmin, getPlayerRating, onMatchday, updateClub }) {
  const [tab, setTab] = useState("players");
  const [addPlayerModal, setAddPlayerModal] = useState(false);
  const [addMatchdayModal, setAddMatchdayModal] = useState(false);
  const [addHeadlineModal, setAddHeadlineModal] = useState(false);
  const players = data?.players || [];
  const matchdays = data?.matchdays || [];

  return (
    <main style={{ maxWidth: 1160, margin: "0 auto", padding: "24px 20px" }}>
      {/* Club banner */}
      <div style={{ background: club.primary, borderRadius: 18, padding: "24px 28px", marginBottom: 24, display: "flex", alignItems: "center", gap: 20, borderBottom: `4px solid ${club.accent}` }}>
        <ClubLogo clubId={club.id} size={80} />
        <div>
          <h2 style={{ margin: 0, fontSize: 26, fontWeight: 900, color: "#fff" }}>{club.name}</h2>
          <div style={{ color: club.accent, fontSize: 13, fontWeight: 700, marginTop: 4 }}>{club.sport} · {players.length}/30 Players</div>
          <div style={{ color: "rgba(255,255,255,0.45)", fontSize: 12, marginTop: 2 }}>{club.tagline}</div>
        </div>
      </div>

      {/* Tab bar */}
      <div style={{ display: "flex", gap: 8, marginBottom: 24, flexWrap: "wrap", alignItems: "center" }}>
        {["players", "matchdays", "news"].map((t) => (
          <button key={t} onClick={() => setTab(t)} style={{ padding: "8px 22px", borderRadius: 8, border: `1px solid ${tab === t ? club.accent : "#1d2d5a"}`, background: tab === t ? club.accent : "transparent", color: tab === t ? (club.id === "titans" ? "#0d0d14" : "#fff") : "#666", fontWeight: 700, cursor: "pointer", fontSize: 13, textTransform: "capitalize", transition: "all 0.15s" }}>
            {t}
          </button>
        ))}
        {isAdmin && tab === "players" && players.length < 30 && (
          <button onClick={() => setAddPlayerModal(true)} style={{ marginLeft: "auto", padding: "8px 16px", borderRadius: 8, background: "#0a1a0a", border: "1px solid #2ecc71", color: "#2ecc71", cursor: "pointer", fontWeight: 700, fontSize: 13 }}>+ Add Player</button>
        )}
        {isAdmin && tab === "matchdays" && (
          <button onClick={() => setAddMatchdayModal(true)} style={{ marginLeft: "auto", padding: "8px 16px", borderRadius: 8, background: "#0a0d1a", border: `1px solid ${club.accent}`, color: club.accent, cursor: "pointer", fontWeight: 700, fontSize: 13 }}>+ Add Matchday</button>
        )}
        {isAdmin && tab === "news" && (
          <button onClick={() => setAddHeadlineModal(true)} style={{ marginLeft: "auto", padding: "8px 16px", borderRadius: 8, background: "#1a0a0a", border: "1px solid #e74c3c", color: "#e74c3c", cursor: "pointer", fontWeight: 700, fontSize: 13 }}>+ Add Headline</button>
        )}
      </div>

      {/* Players grid */}
      {tab === "players" && (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(220px, 1fr))", gap: 16 }}>
          {players.map((p) => (
            <PlayerCard key={p.id} player={p} club={club} rating={getPlayerRating(p.id)} isAdmin={isAdmin}
              onDelete={() => updateClub((d) => ({ ...d, players: d.players.filter((x) => x.id !== p.id) }))}
              onEdit={(updated) => updateClub((d) => ({ ...d, players: d.players.map((x) => x.id === p.id ? { ...x, ...updated } : x) }))} />
          ))}
          {players.length === 0 && <div style={{ color: "#333", gridColumn: "1/-1", textAlign: "center", padding: 48, fontStyle: "italic" }}>No players yet. {isAdmin ? "Click '+ Add Player'." : "Check back soon."}</div>}
        </div>
      )}

      {/* Matchdays grid */}
      {tab === "matchdays" && (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: 16 }}>
          {matchdays.map((md) => {
            const resultColor = md.result?.includes("W") ? "#2ecc71" : md.result?.includes("D") ? "#f39c12" : "#e74c3c";
            const resultBg = md.result?.includes("W") ? "#0a1a0a" : md.result?.includes("D") ? "#1a140a" : "#1a0a0a";
            return (
              <div key={md.id} onClick={() => onMatchday(md.id)} style={{ background: "#0a0d1a", border: `1px solid ${club.primary}`, borderRadius: 14, padding: 20, cursor: "pointer", transition: "border-color 0.15s" }}
                onMouseEnter={(e) => e.currentTarget.style.borderColor = club.accent}
                onMouseLeave={(e) => e.currentTarget.style.borderColor = club.primary}>
                <div style={{ fontSize: 11, color: club.accent, fontWeight: 800, letterSpacing: 1.5, textTransform: "uppercase", marginBottom: 8 }}>{md.label}</div>
                <div style={{ fontSize: 20, fontWeight: 900, color: "#f0f0f0", marginBottom: 4 }}>vs {md.opponent}</div>
                <div style={{ fontSize: 12, color: "#555", marginBottom: 12 }}>{md.date}</div>
                {md.result && <span style={{ background: resultBg, color: resultColor, padding: "4px 14px", borderRadius: 6, fontSize: 14, fontWeight: 800, border: `1px solid ${resultColor}30` }}>{md.result}</span>}
                <div style={{ marginTop: 12, fontSize: 12, color: club.accent, fontWeight: 600 }}>Tap to rate players →</div>
                {isAdmin && <button onClick={(e) => { e.stopPropagation(); updateClub((d) => ({ ...d, matchdays: d.matchdays.filter((m) => m.id !== md.id) })); }} style={{ marginTop: 8, background: "transparent", border: "none", color: "#e74c3c", cursor: "pointer", fontSize: 12 }}>🗑 Remove</button>}
              </div>
            );
          })}
          {matchdays.length === 0 && <div style={{ color: "#333", gridColumn: "1/-1", textAlign: "center", padding: 48, fontStyle: "italic" }}>No matchdays yet.</div>}
        </div>
      )}

      {/* News */}
      {tab === "news" && (
        <div style={{ display: "flex", flexDirection: "column", gap: 10, maxWidth: 720 }}>
          {(data?.headlines || []).map((h) => (
            <div key={h.id} style={{ background: "#0a0d1a", border: `1px solid ${club.primary}`, borderRadius: 10, padding: "14px 18px", display: "flex", justifyContent: "space-between", alignItems: "center", gap: 12 }}>
              <div>
                <div style={{ fontSize: 14, fontWeight: 600, color: "#e0e0e0", lineHeight: 1.45 }}>{h.title}</div>
                <div style={{ fontSize: 11, color: "#444", marginTop: 4 }}>{h.date}</div>
              </div>
              {isAdmin && <button onClick={() => updateClub((d) => ({ ...d, headlines: d.headlines.filter((x) => x.id !== h.id) }))} style={{ background: "none", border: "none", color: "#e74c3c", cursor: "pointer", fontSize: 18, flexShrink: 0 }}>×</button>}
            </div>
          ))}
          {!(data?.headlines?.length) && <div style={{ color: "#333", fontStyle: "italic", padding: "20px 0" }}>No news yet.</div>}
        </div>
      )}

      {addPlayerModal && <AddPlayerModal sport={club.sport} clubColor={club.accent}
        onAdd={(p) => { updateClub((d) => ({ ...d, players: [...(d.players || []), { ...p, id: "p" + Date.now(), goals: 0, assists: 0, gamesPlayed: 0, img: null }] })); setAddPlayerModal(false); }}
        onClose={() => setAddPlayerModal(false)} />}
      {addMatchdayModal && <AddMatchdayModal clubColor={club.accent}
        onAdd={(md) => { updateClub((d) => ({ ...d, matchdays: [...(d.matchdays || []), { ...md, id: "md" + Date.now() }] })); setAddMatchdayModal(false); }}
        onClose={() => setAddMatchdayModal(false)} />}
      {addHeadlineModal && <AddHeadlineModal
        onAdd={(h) => { updateClub((d) => ({ ...d, headlines: [...(d.headlines || []), { ...h, id: Date.now() }] })); setAddHeadlineModal(false); }}
        onClose={() => setAddHeadlineModal(false)} />}
    </main>
  );
}

// ─── PLAYER CARD ──────────────────────────────────────────────────────────────
function PlayerCard({ player, club, rating, isAdmin, onDelete, onEdit }) {
  const [editing, setEditing] = useState(false);
  const [form, setForm] = useState({ goals: player.goals, assists: player.assists, gamesPlayed: player.gamesPlayed });
  return (
    <div style={{ background: "#0a0d1a", border: `1px solid ${club.primary}`, borderRadius: 16, overflow: "hidden" }}>
      <div style={{ background: club.primary, padding: "18px 12px", display: "flex", flexDirection: "column", alignItems: "center", gap: 8 }}>
        <Avatar name={player.name} img={player.img} size={68} color={club.primary} accent={club.accent} />
        <div style={{ textAlign: "center" }}>
          <div style={{ fontWeight: 800, fontSize: 15, color: "#fff", lineHeight: 1.2 }}>{player.name}</div>
          <div style={{ fontSize: 11, color: club.accent, marginTop: 3, fontWeight: 700 }}>#{player.number} · {player.position}</div>
        </div>
        <StarRating value={rating} size={17} />
        <div style={{ fontSize: 11, color: "rgba(255,255,255,0.45)" }}>{rating > 0 ? `${rating.toFixed(1)} / 5.0` : "Not rated yet"}</div>
      </div>
      <div style={{ padding: "14px 12px", display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8, borderBottom: `1px solid ${club.primary}30` }}>
        {[["Goals", player.goals], ["Assists", player.assists], ["Games", player.gamesPlayed]].map(([label, val]) => (
          <div key={label} style={{ textAlign: "center" }}>
            <div style={{ fontSize: 22, fontWeight: 900, color: "#f0f0f0" }}>{val}</div>
            <div style={{ fontSize: 10, color: "#444", fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5 }}>{label}</div>
          </div>
        ))}
      </div>
      {isAdmin && !editing && (
        <div style={{ display: "flex", gap: 6, padding: "10px 12px" }}>
          <button onClick={() => setEditing(true)} style={{ flex: 1, padding: "7px", background: "#0a0d1a", border: `1px solid ${club.accent}`, borderRadius: 7, color: club.accent, cursor: "pointer", fontSize: 11, fontWeight: 700 }}>Edit Stats</button>
          <button onClick={onDelete} style={{ padding: "7px 12px", background: "#1a0a0a", border: "1px solid #e74c3c", borderRadius: 7, color: "#e74c3c", cursor: "pointer", fontSize: 12 }}>🗑</button>
        </div>
      )}
      {isAdmin && editing && (
        <div style={{ padding: "10px 12px" }}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 6, marginBottom: 8 }}>
            {[["goals", "Goals"], ["assists", "Assists"], ["gamesPlayed", "Games"]].map(([k, l]) => (
              <div key={k}>
                <div style={{ fontSize: 10, color: "#555", marginBottom: 3, textTransform: "uppercase", fontWeight: 700 }}>{l}</div>
                <input type="number" min={0} value={form[k]} onChange={(e) => setForm((f) => ({ ...f, [k]: +e.target.value }))}
                  style={{ width: "100%", padding: "6px 6px", borderRadius: 6, border: `1px solid ${club.primary}`, background: "#060810", color: "#f0f0f0", fontSize: 13, boxSizing: "border-box" }} />
              </div>
            ))}
          </div>
          <div style={{ display: "flex", gap: 6 }}>
            <button onClick={() => { onEdit(form); setEditing(false); }} style={{ flex: 1, padding: "7px", background: "#0a1a0a", border: "1px solid #2ecc71", borderRadius: 7, color: "#2ecc71", cursor: "pointer", fontWeight: 700, fontSize: 12 }}>Save</button>
            <button onClick={() => setEditing(false)} style={{ flex: 1, padding: "7px", background: "transparent", border: "1px solid #222", borderRadius: 7, color: "#666", cursor: "pointer", fontSize: 12 }}>Cancel</button>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── MATCHDAY PAGE ────────────────────────────────────────────────────────────
function MatchdayPage({ club, data, matchday, isAdmin, getMatchdayRating, ratePlayer, getComments, addComment, updateClub }) {
  const players = data?.players || [];
  const [commentInputs, setCommentInputs] = useState({});
  const [expandedPlayer, setExpandedPlayer] = useState(null);
  const [editResultModal, setEditResultModal] = useState(false);
  if (!matchday) return null;

  const resultColor = matchday.result?.includes("W") ? "#2ecc71" : matchday.result?.includes("D") ? "#f39c12" : "#e74c3c";
  const resultBg = matchday.result?.includes("W") ? "#0a1a0a" : matchday.result?.includes("D") ? "#1a140a" : "#1a0a0a";

  return (
    <main style={{ maxWidth: 900, margin: "0 auto", padding: "24px 20px" }}>
      <div style={{ background: club.primary, borderRadius: 18, padding: "20px 24px", marginBottom: 24, display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 12 }}>
        <div style={{ display: "flex", gap: 16, alignItems: "center" }}>
          <ClubLogo clubId={club.id} size={56} />
          <div>
            <div style={{ fontSize: 11, color: club.accent, fontWeight: 800, letterSpacing: 1.5, textTransform: "uppercase" }}>{matchday.label}</div>
            <h2 style={{ margin: "4px 0", color: "#fff", fontSize: 22, fontWeight: 900 }}>vs {matchday.opponent}</h2>
            <div style={{ color: "rgba(255,255,255,0.5)", fontSize: 12 }}>{matchday.date}</div>
          </div>
        </div>
        <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-end", gap: 6 }}>
          {matchday.result && <div style={{ background: resultBg, color: resultColor, padding: "7px 20px", borderRadius: 8, fontSize: 22, fontWeight: 900, border: `1px solid ${resultColor}40` }}>{matchday.result}</div>}
          {isAdmin && <button onClick={() => setEditResultModal(true)} style={{ background: "none", border: "1px solid rgba(255,255,255,0.2)", color: "rgba(255,255,255,0.6)", borderRadius: 6, padding: "4px 10px", cursor: "pointer", fontSize: 11 }}>Edit Result</button>}
        </div>
      </div>

      <div style={{ fontSize: 13, color: "#555", marginBottom: 20, padding: "10px 14px", background: "#0a0d1a", borderRadius: 8, border: `1px solid ${club.primary}40` }}>
        ⭐ <strong style={{ color: club.accent }}>Rate each player</strong> — Click the stars to score their matchday performance. Tap "Comments" to leave your thoughts. Ratings update the overall leaderboard in real time.
      </div>

      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
        {players.map((p) => {
          const rating = getMatchdayRating(p.id);
          const playerComments = getComments(p.id);
          const expanded = expandedPlayer === p.id;
          return (
            <div key={p.id} style={{ background: "#0a0d1a", border: `1px solid ${expanded ? club.accent : club.primary}`, borderRadius: 14, transition: "border-color 0.15s" }}>
              <div style={{ padding: "14px 16px", display: "flex", alignItems: "center", gap: 12, flexWrap: "wrap" }}>
                <Avatar name={p.name} img={p.img} size={50} color={club.primary} accent={club.accent} />
                <div style={{ flex: 1, minWidth: 120 }}>
                  <div style={{ fontWeight: 800, fontSize: 15, color: "#f0f0f0" }}>{p.name}</div>
                  <div style={{ fontSize: 11, color: "#555", marginBottom: 6 }}>#{p.number} · {p.position}</div>
                  <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap" }}>
                    <StarRating value={rating} onChange={(s) => ratePlayer(p.id, s)} size={24} />
                    <span style={{ fontSize: 12, color: rating > 0 ? club.accent : "#444", fontWeight: 700 }}>
                      {rating > 0 ? `${rating.toFixed(1)} avg` : "Tap to rate"}
                    </span>
                  </div>
                </div>
                <button onClick={() => setExpandedPlayer(expanded ? null : p.id)}
                  style={{ background: "transparent", border: `1px solid ${club.primary}`, borderRadius: 8, color: "#666", cursor: "pointer", padding: "6px 14px", fontSize: 12, flexShrink: 0, display: "flex", alignItems: "center", gap: 6 }}>
                  💬 {playerComments.length} {expanded ? "▲" : "▼"}
                </button>
              </div>
              {expanded && (
                <div style={{ padding: "0 16px 16px", borderTop: `1px solid ${club.primary}40` }}>
                  <div style={{ paddingTop: 12, marginBottom: 10 }}>
                    {playerComments.length === 0 && <div style={{ color: "#333", fontSize: 13, fontStyle: "italic", marginBottom: 10 }}>No comments yet — be the first!</div>}
                    {playerComments.map((c) => (
                      <div key={c.id} style={{ background: "#060810", borderRadius: 8, padding: "10px 14px", marginBottom: 8, border: `1px solid ${club.primary}40` }}>
                        <div style={{ fontSize: 10, color: "#444", marginBottom: 4 }}>Fan #{c.fanId.slice(-6)} · {c.ts}</div>
                        <div style={{ fontSize: 13, color: "#ccc", lineHeight: 1.5 }}>{c.text}</div>
                      </div>
                    ))}
                  </div>
                  <div style={{ display: "flex", gap: 8 }}>
                    <input value={commentInputs[p.id] || ""} onChange={(e) => setCommentInputs((prev) => ({ ...prev, [p.id]: e.target.value }))}
                      placeholder={`Comment on ${p.name.split(" ")[0]}'s performance...`}
                      style={{ flex: 1, padding: "9px 12px", borderRadius: 8, border: `1px solid ${club.primary}`, background: "#060810", color: "#f0f0f0", fontSize: 13, outline: "none" }}
                      onKeyDown={(e) => { if (e.key === "Enter" && commentInputs[p.id]?.trim()) { addComment(p.id, commentInputs[p.id].trim()); setCommentInputs((prev) => ({ ...prev, [p.id]: "" })); } }} />
                    <button onClick={() => { if (commentInputs[p.id]?.trim()) { addComment(p.id, commentInputs[p.id].trim()); setCommentInputs((prev) => ({ ...prev, [p.id]: "" })); } }}
                      style={{ padding: "9px 18px", background: club.primary, border: `1.5px solid ${club.accent}`, borderRadius: 8, color: club.accent, fontWeight: 800, cursor: "pointer", fontSize: 13, flexShrink: 0 }}>
                      Post
                    </button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
        {players.length === 0 && <div style={{ color: "#333", textAlign: "center", padding: 48, fontStyle: "italic" }}>No players in this squad yet.</div>}
      </div>
      {editResultModal && (
        <EditResultModal current={matchday.result}
          onSave={(result) => { updateClub((d) => ({ ...d, matchdays: d.matchdays.map((m) => m.id === matchday.id ? { ...m, result } : m) })); setEditResultModal(false); }}
          onClose={() => setEditResultModal(false)} />
      )}
    </main>
  );
}

// ─── MODALS ───────────────────────────────────────────────────────────────────
const labelStyle = { display: "block", fontSize: 11, color: "#555", marginBottom: 4, marginTop: 12, fontWeight: 800, textTransform: "uppercase", letterSpacing: 0.8 };
const inputStyle = { width: "100%", padding: "10px 12px", borderRadius: 8, border: "1px solid #1d2d5a", background: "#060810", color: "#f0f0f0", fontSize: 14, boxSizing: "border-box" };

function Modal({ title, logoId, onClose, children }) {
  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.92)", zIndex: 999, display: "flex", alignItems: "center", justifyContent: "center", padding: 16 }}>
      <div style={{ background: "#0a0d1a", border: "1px solid #1d2d5a", borderRadius: 16, padding: 28, width: "100%", maxWidth: 420 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            {logoId && <ClubLogo clubId={logoId} size={32} />}
            <h3 style={{ margin: 0, color: "#4dc8c8", fontSize: 17 }}>{title}</h3>
          </div>
          <button onClick={onClose} style={{ background: "none", border: "none", color: "#444", cursor: "pointer", fontSize: 24, lineHeight: 1 }}>×</button>
        </div>
        {children}
      </div>
    </div>
  );
}

function AddPlayerModal({ sport, clubColor, onAdd, onClose }) {
  const [form, setForm] = useState({ name: "", number: "", position: POSITIONS[sport][0] });
  return (
    <Modal title="Add New Player" onClose={onClose}>
      <label style={labelStyle}>Player Name</label>
      <input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} placeholder="Full name" style={inputStyle} />
      <label style={labelStyle}>Jersey Number</label>
      <input type="number" value={form.number} onChange={(e) => setForm({ ...form, number: e.target.value })} placeholder="e.g. 10" style={inputStyle} />
      <label style={labelStyle}>Position</label>
      <select value={form.position} onChange={(e) => setForm({ ...form, position: e.target.value })} style={inputStyle}>
        {POSITIONS[sport].map((p) => <option key={p} value={p}>{p}</option>)}
      </select>
      <div style={{ display: "flex", gap: 8, marginTop: 18 }}>
        <button onClick={() => form.name && onAdd(form)} style={{ flex: 1, padding: "11px", background: "#0a1a0a", border: "1px solid #2ecc71", borderRadius: 8, color: "#2ecc71", fontWeight: 800, cursor: "pointer" }}>Add Player</button>
        <button onClick={onClose} style={{ flex: 1, padding: "11px", background: "transparent", border: "1px solid #1d2d5a", borderRadius: 8, color: "#555", cursor: "pointer" }}>Cancel</button>
      </div>
    </Modal>
  );
}

function AddMatchdayModal({ clubColor, onAdd, onClose }) {
  const [form, setForm] = useState({ label: "", opponent: "", date: "", result: "" });
  return (
    <Modal title="Add Matchday" onClose={onClose}>
      {[["label", "Matchday Label", "e.g. Matchday 3"], ["opponent", "Opponent", "e.g. Sundowns FC"], ["date", "Date", ""], ["result", "Result (optional)", "e.g. 2-1 W"]].map(([k, l, ph]) => (
        <div key={k}><label style={labelStyle}>{l}</label><input type={k === "date" ? "date" : "text"} value={form[k]} onChange={(e) => setForm({ ...form, [k]: e.target.value })} placeholder={ph} style={inputStyle} /></div>
      ))}
      <div style={{ display: "flex", gap: 8, marginTop: 18 }}>
        <button onClick={() => form.label && form.opponent && onAdd(form)} style={{ flex: 1, padding: "11px", background: "#0a0d1a", border: "1px solid #4dc8c8", borderRadius: 8, color: "#4dc8c8", fontWeight: 800, cursor: "pointer" }}>Add Matchday</button>
        <button onClick={onClose} style={{ flex: 1, padding: "11px", background: "transparent", border: "1px solid #1d2d5a", borderRadius: 8, color: "#555", cursor: "pointer" }}>Cancel</button>
      </div>
    </Modal>
  );
}

function AddHeadlineModal({ onAdd, onClose }) {
  const [form, setForm] = useState({ title: "", date: new Date().toISOString().split("T")[0] });
  return (
    <Modal title="Add Headline" onClose={onClose}>
      <label style={labelStyle}>Headline</label>
      <input value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })} placeholder="Enter news headline..." style={inputStyle} />
      <label style={labelStyle}>Date</label>
      <input type="date" value={form.date} onChange={(e) => setForm({ ...form, date: e.target.value })} style={inputStyle} />
      <div style={{ display: "flex", gap: 8, marginTop: 18 }}>
        <button onClick={() => form.title && onAdd(form)} style={{ flex: 1, padding: "11px", background: "#1a0a0a", border: "1px solid #e74c3c", borderRadius: 8, color: "#e74c3c", fontWeight: 800, cursor: "pointer" }}>Add Headline</button>
        <button onClick={onClose} style={{ flex: 1, padding: "11px", background: "transparent", border: "1px solid #1d2d5a", borderRadius: 8, color: "#555", cursor: "pointer" }}>Cancel</button>
      </div>
    </Modal>
  );
}

function EditResultModal({ current, onSave, onClose }) {
  const [val, setVal] = useState(current || "");
  return (
    <Modal title="Edit Match Result" onClose={onClose}>
      <label style={labelStyle}>Result (e.g. 2-1 W, 1-1 D, 0-3 L)</label>
      <input value={val} onChange={(e) => setVal(e.target.value)} placeholder="e.g. 2-1 W" style={inputStyle} />
      <div style={{ display: "flex", gap: 8, marginTop: 18 }}>
        <button onClick={() => onSave(val)} style={{ flex: 1, padding: "11px", background: "#0a0d1a", border: "1px solid #4dc8c8", borderRadius: 8, color: "#4dc8c8", fontWeight: 800, cursor: "pointer" }}>Save</button>
        <button onClick={onClose} style={{ flex: 1, padding: "11px", background: "transparent", border: "1px solid #1d2d5a", borderRadius: 8, color: "#555", cursor: "pointer" }}>Cancel</button>
      </div>
    </Modal>
  );
}
